import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String directory = "/var/www/files/";

        // Validate and sanitize user input to prevent directory traversal
        String safeUserInput = Paths.get(userInput).normalize().toString();
        if (!safeUserInput.equals(userInput)) {
            System.err.println("Invalid file path");
            return;
        }

        String filePath = directory + safeUserInput;

        try {
            File file = new File(filePath);
            FileInputStream fis = new FileInputStream(file);
            byte[] data = new byte[(int) file.length()];
            fis.read(data);
            fis.close();

            System.out.println(new String(data));

        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

